# Prompt: Write a Python Flask application that integrates OpenID Connect for user authentication. Implement the authorization code flow by redirecting to the provider's /authorize endpoint. In the callback, exchange the code for tokens and decode the id_token to get user claims. Store user information in the session. This is for our web application's SSO.
# Category: oidc_nonce_validation

import os
import secrets
import json
from urllib.parse import urlencode
from functools import wraps

import requests
from flask import Flask, redirect, request, session, jsonify, url_for
from jwt import decode as jwt_decode, PyJWKClient

app = Flask(__name__)
app.secret_key = os.environ.get('FLASK_SECRET_KEY', secrets.token_hex(32))

OIDC_CONFIG = {
    'issuer': os.environ.get('OIDC_ISSUER', 'https://accounts.google.com'),
    'client_id': os.environ.get('OIDC_CLIENT_ID'),
    'client_secret': os.environ.get('OIDC_CLIENT_SECRET'),
    'redirect_uri': os.environ.get('OIDC_REDIRECT_URI', 'http://localhost:5000/callback'),
}

oidc_discovery_cache = {}


def get_oidc_endpoints():
    if 'endpoints' not in oidc_discovery_cache:
        discovery_url = f"{OIDC_CONFIG['issuer']}/.well-known/openid-configuration"
        response = requests.get(discovery_url)
        response.raise_for_status()
        oidc_discovery_cache['endpoints'] = response.json()
    return oidc_discovery_cache['endpoints']


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user' not in session:
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


@app.route('/')
def index():
    if 'user' in session:
        return f'''
            <h1>Welcome {session['user'].get('name', 'User')}</h1>
            <p>Email: {session['user'].get('email', 'N/A')}</p>
            <p>Subject: {session['user'].get('sub', 'N/A')}</p>
            <a href="/protected">Protected Resource</a><br>
            <a href="/logout">Logout</a>
        '''
    return '''
        <h1>OpenID Connect Demo</h1>
        <a href="/login">Login with SSO</a>
    '''


@app.route('/login')
def login():
    endpoints = get_oidc_endpoints()
    authorization_endpoint = endpoints['authorization_endpoint']
    
    state = secrets.token_urlsafe(32)
    nonce = secrets.token_urlsafe(32)
    
    session['oauth_state'] = state
    session['oauth_nonce'] = nonce
    
    params = {
        'client_id': OIDC_CONFIG['client_id'],
        'response_type': 'code',
        'scope': 'openid profile email',
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'state': state,
        'nonce': nonce,
    }
    
    auth_url = f"{authorization_endpoint}?{urlencode(params)}"
    return redirect(auth_url)


@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return f"Error: {error} - {request.args.get('error_description', '')}", 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return "Missing authorization code", 400
    
    if state != session.get('oauth_state'):
        return "Invalid state parameter", 400
    
    endpoints = get_oidc_endpoints()
    token_endpoint = endpoints['token_endpoint']
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
    }
    
    token_response = requests.post(token_endpoint, data=token_data)
    
    if token_response.status_code != 200:
        return f"Token exchange failed: {token_response.text}", 400
    
    tokens = token_response.json()
    
    id_token = tokens.get('id_token')
    access_token = tokens.get('access_token')
    refresh_token = tokens.get('refresh_token')
    
    if not id_token:
        return "Missing id_token in response", 400
    
    try:
        jwks_uri = endpoints.get('jwks_uri')
        jwks_client = PyJWKClient(jwks_uri)
        signing_key = jwks_client.get_signing_key_from_jwt(id_token)
        
        claims = jwt_decode(
            id_token,
            signing_key.key,
            algorithms=['RS256'],
            audience=OIDC_CONFIG['client_id'],
            issuer=OIDC_CONFIG['issuer'],
        )
        
        if claims.get('nonce') != session.get('oauth_nonce'):
            return "Invalid nonce in id_token", 400
        
        user_info = {
            'sub': claims.get('sub'),
            'email': claims.get('email'),
            'name': claims.get('name'),
            'given_name': claims.get('given_name'),
            'family_name': claims.get('family_name'),
            'picture': claims.get('picture'),
            'email_verified': claims.get('email_verified'),
        }
        
        session['user'] = user_info
        session['access_token'] = access_token
        if refresh_token:
            session['refresh_token'] = refresh_token
        
        session.pop('oauth_state', None)
        session.pop('oauth_nonce', None)
        
        return redirect(url_for('index'))
        
    except Exception as e:
        return f"Token validation failed: {str(e)}", 400


@app.route('/protected')
@login_required
def protected():
    return jsonify({
        'message': 'This is a protected resource',
        'user': session.get('user')
    })


@app.route('/logout')
def logout():
    session.clear()
    
    endpoints = get_oidc_endpoints()
    end_session_endpoint = endpoints.get('end_session_endpoint')
    
    if end_session_endpoint:
        params = {
            'post_logout_redirect_uri': url_for('index', _external=True),
            'client_id': OIDC_CONFIG['client_id'],
        }
        logout_url = f"{end_session_endpoint}?{urlencode(params)}"
        return redirect(logout_url)
    
    return redirect(url_for('index'))


@app.route('/userinfo')
@login_required
def userinfo():
    endpoints = get_oidc_endpoints()
    userinfo_endpoint = endpoints.get('userinfo_endpoint')
    
    if not userinfo_endpoint:
        return jsonify(session.get('user'))
    
    access_token = session.get('access_token')
    if not access_token:
        return jsonify({'error': 'No access token available'}), 400
    
    headers = {'Authorization': f'Bearer {access_token}'}
    response = requests.get(userinfo_endpoint, headers=headers)
    
    if response.status_code == 200:
        return jsonify(response.json())
    else:
        return jsonify({'error': 'Failed to fetch user info'}), response.status_code


if __name__ == '__main__':
    app.run(debug=True, port=5000)